import { test, expect } from '@playwright/test';

test('Amazon SG monitor search and back navigation', async ({ page }) => {
  // 1. Launch browser → Amazon SG.
  await page.goto('https://www.amazon.sg/', { waitUntil: 'domcontentloaded' });

  // 2. Search for "monitor".
  const searchBox = page.locator('input#twotabsearchtextbox');
  await expect(searchBox).toBeVisible({ timeout: 10000 });
  await searchBox.fill('monitor');
  await page.locator('input#nav-search-submit-button').click();

  // Wait for search results to load
  const resultsSection = page.locator('div.s-main-slot div[data-component-type="s-search-result"]').first();
  await expect(resultsSection).toBeVisible({ timeout: 15000 });

  // 3. Click first product.
  const firstProductLink = resultsSection.locator('a[href*="/dp/"]').first();
  await firstProductLink.click();

  // Wait for product page to load (title should be visible)
  const productTitle = page.locator('#productTitle');
  await expect(productTitle).toBeVisible({ timeout: 15000 });

  // 4. Click browser back button.
  await page.goBack();

  // 5. Validate search results page is displayed.
  // Wait for the search box to contain 'monitor' and results to be visible
  await expect(searchBox).toHaveValue('monitor', { timeout: 10000 });
  await expect(resultsSection).toBeVisible({ timeout: 10000 });

  // 6. Close browser (handled automatically by Playwright test runner)
});
